import React, { useState, useEffect } from 'react';
import { Search, ShoppingCart, Star, Filter } from 'lucide-react';
//import './ProductsPage.css';

const ProductsPage = ({
	products,
	searchQuery,
	setSearchQuery,
	user,
	addToCart,
	setCurrentPage,
	setLoading,
	setError
}) => {
	const [filteredProducts, setFilteredProducts] = useState([]);
	const [currentSlide, setCurrentSlide] = useState(0);
	const [selectedCategory, setSelectedCategory] = useState('all');
	const [sortBy, setSortBy] = useState('featured');

	// Offer banners for sliding carousel
	const offerBanners = [
		{ id: 1, title: 'MEGA SALE', discount: '50% OFF', color: '#FF6B6B' },
		{ id: 2, title: 'LIMITED TIME', discount: 'Upto 70% OFF', color: '#4ECDC4' },
		{ id: 3, title: 'FLASH DEAL', discount: 'Extra 20% OFF', color: '#FFE66D' },
		{ id: 4, title: 'NEW YEAR SPECIAL', discount: 'Flat ₹1000 OFF', color: '#95E1D3' }
	];

	// Auto-slide banner
	useEffect(() => {
		const timer = setInterval(() => {
			setCurrentSlide((prev) => (prev + 1) % offerBanners.length);
		}, 4000);
		return () => clearInterval(timer);
	}, [offerBanners.length]);

	// Filter and sort products
	useEffect(() => {
		let result = products || [];

		if (searchQuery) {
			result = result.filter(p =>
				p.name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
				p.description?.toLowerCase().includes(searchQuery.toLowerCase())
			);
		}

		if (selectedCategory !== 'all') {
			result = result.filter(p => p.category?.toLowerCase() === selectedCategory.toLowerCase());
		}

		// Sort products
		switch (sortBy) {
			case 'price-low':
				result.sort((a, b) => a.price - b.price);
				break;
			case 'price-high':
				result.sort((a, b) => b.price - a.price);
				break;
			case 'rating':
				result.sort((a, b) => (b.rating || 0) - (a.rating || 0));
				break;
			default:
				break;
		}

		setFilteredProducts(result);
	}, [products, searchQuery, selectedCategory, sortBy]);

	const handleAddToCart = async (product) => {
		try {
			setLoading(true);
			await addToCart({
				productId: product.productId || product.id,
				quantity: 1
			});
			setError('');
		} catch (err) {
			setError('Failed to add item to cart');
			console.error(err);
		} finally {
			setLoading(false);
		}
	};

	const categories = ['all', 'Electronics', 'Fashion', 'Home', 'Books', 'Sports'];

	return (
		<div className="products-page">
			{/* Header */}
			<header className="products-header">
				<div className="header-content">
					<h1>Welcome, {user?.fullName || 'Customer'}!</h1>
					<div className="search-bar">
						<input
							type="text"
							placeholder="Search products..."
							value={searchQuery}
							onChange={(e) => setSearchQuery(e.target.value)}
							className="search-input"
						/>
						<button className="search-btn">🔍</button>
					</div>
				</div>
			</header>

			{/* Sliding Offer Banner */}
			<section className="offer-banner-section">
				<div className="banner-carousel">
					{offerBanners.map((banner, index) => (
						<div
							key={banner.id}
							className={`banner-slide ${index === currentSlide ? 'active' : ''}`}
							style={{ backgroundColor: banner.color }}
						>
							<div className="banner-content">
								<h2>{banner.title}</h2>
								<p className="banner-discount">{banner.discount}</p>
								<button className="banner-btn">Shop Now</button>
							</div>
						</div>
					))}
				</div>

				{/* Carousel Controls */}
				<div className="carousel-controls">
					{offerBanners.map((_, index) => (
						<button
							key={index}
							className={`dot ${index === currentSlide ? 'active' : ''}`}
							onClick={() => setCurrentSlide(index)}
						/>
					))}
				</div>
			</section>

			{/* Filters & Sorting */}
			<section className="filters-section">
				<div className="category-filter">
					<h3>Categories</h3>
					<div className="category-list">
						{categories.map(cat => (
							<button
								key={cat}
								className={`category-btn ${selectedCategory === cat ? 'active' : ''}`}
								onClick={() => setSelectedCategory(cat)}
							>
								{cat.charAt(0).toUpperCase() + cat.slice(1)}
							</button>
						))}
					</div>
				</div>

				<div className="sort-filter">
					<label>Sort By:</label>
					<select value={sortBy} onChange={(e) => setSortBy(e.target.value)}>
						<option value="featured">Featured</option>
						<option value="price-low">Price: Low to High</option>
						<option value="price-high">Price: High to Low</option>
						<option value="rating">Highest Rating</option>
					</select>
				</div>
			</section>

			{/* Products Grid */}
			<section className="products-section">
				<div className="results-info">
					<p>Showing {filteredProducts.length} products</p>
				</div>

				<div className="products-grid">
					{filteredProducts.length > 0 ? (
						filteredProducts.map(product => (
							<div key={product.id || product.productId} className="product-card">
								<div className="product-image">
									<img
										src={product.imageUrl || '🖼️'}
										alt={product.name}
										onError={(e) => (e.target.src = '🖼️')}
									/>
									{product.discount && (
										<span className="discount-badge">{product.discount}% OFF</span>
									)}
								</div>

								<div className="product-details">
									<h3 className="product-name">{product.name}</h3>
									<p className="product-desc">{product.description?.substring(0, 50)}...</p>

									<div className="product-rating">
										<span className="stars">{'⭐'.repeat(Math.min(product.rating || 4, 5))}</span>
										<span className="rating-text">({product.reviews || 0})</span>
									</div>

									<div className="product-price">
										<span className="current-price">₹{product.price}</span>
										{product.originalPrice && (
											<span className="original-price">₹{product.originalPrice}</span>
										)}
									</div>

									<button
										className="add-to-cart-btn"
										onClick={() => handleAddToCart(product)}
									>
										🛒 Add to Cart
									</button>
								</div>
							</div>
						))
					) : (
						<div className="no-products">
							<p>No products found. Try adjusting your filters.</p>
						</div>
					)}
				</div>
			</section>
		</div>
	);
};

export default ProductsPage;
